--
-- Estructura de tabla para la tabla `analisis_laborales`
--

CREATE TABLE `analisis_laborales` (
  `id` int(11) NOT NULL,
  `uuid` varchar(36) NOT NULL,
  `tipo_usuario` enum('empleado','empleador') NOT NULL,
  `tipo_conflicto` varchar(80) NOT NULL,
  `datos_laborales` longtext NOT NULL COMMENT 'JSON: salario, antiguedad, provincia, categoria, cct',
  `documentacion_json` longtext NOT NULL COMMENT 'JSON: telegramas, recibos, testigos, afip',
  `situacion_json` longtext NOT NULL COMMENT 'JSON: plazo, intercambio, urgencia',
  `iril_score` decimal(3,1) NOT NULL DEFAULT 0.0,
  `iril_detalle` longtext DEFAULT NULL COMMENT 'JSON: desglose por dimension',
  `exposicion_json` longtext DEFAULT NULL COMMENT 'JSON: montos estimados LCT por concepto',
  `escenario_recomendado` char(1) DEFAULT NULL COMMENT 'A, B, C o D',
  `escenarios_json` longtext DEFAULT NULL COMMENT 'JSON: array con los 4 escenarios',
  `accion_tomada` enum('ver_informe','contacto','tramite','ninguna') DEFAULT 'ninguna',
  `tramite_uuid` varchar(36) DEFAULT NULL COMMENT 'UUID del tramite si se derivó al sistema principal',
  `email` varchar(200) DEFAULT NULL,
  `ip` varchar(45) NOT NULL,
  `fecha_creacion` timestamp NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

