CREATE TABLE `certificados_trabajo_digitales` (
  `id` int(11) NOT NULL,
  `uuid` varchar(36) NOT NULL,
  `numero_certificado` varchar(30) DEFAULT NULL,
  `cuil_trabajador` varchar(11) NOT NULL,
  `periodo_desde` date NOT NULL,
  `periodo_hasta` date NOT NULL,
  `tipo_certificado` enum('formato_clasico','codigo_qr','blockchain_hash') DEFAULT 'formato_clasico',
  `valido_segun_art80` enum('si','no','cuestionable') DEFAULT 'si',
  `motivo_rechazo` text DEFAULT NULL,
  `custodia_trabajador` tinyint(1) DEFAULT 1,
  `custodia_empleador` tinyint(1) DEFAULT 1,
  `custodia_tercero` text DEFAULT NULL,
  `expedido_por` varchar(100) DEFAULT NULL,
  `fecha_expedicion` date DEFAULT NULL,
  `acto_administrativo` tinyint(1) DEFAULT 0,
  `activo` tinyint(1) DEFAULT 1,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

