--
-- Estructura de tabla para la tabla `pro_ccts`
--

CREATE TABLE `pro_ccts` (
  `id` int(11) NOT NULL,
  `cct_codigo` varchar(50) NOT NULL,
  `cct_nombre` varchar(255) NOT NULL,
  `antiguedad` text DEFAULT NULL,
  `presentismo` text DEFAULT NULL,
  `adicionales` text DEFAULT NULL,
  `notas` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `pro_ccts`
--

INSERT INTO `pro_ccts` (`id`, `cct_codigo`, `cct_nombre`, `antiguedad`, `presentismo`, `adicionales`, `notas`) VALUES
(1, '130/75', 'Empleados de Comercio', '1% por año aniversario (Art. 24)', '8.33% sobre la remuneración mensual (Art. 40)', 'Fallo de Caja (Cajeros A/B/C), Choferes, Vidrieristas', 'Jornada legal de 48 hs. Fuerte incidencia de sumas no remunerativas pactadas en paritarias que luego se incorporan al básico.'),
(2, '260/75', 'Metalúrgico (UOM)', '1% por año (hasta 20 años) s/ básico', 'Premio por asistencia y puntualidad variable según rama', 'Título técnico, turno, insalubridad. Ingreso Mínimo Global de Referencia (IMGR).', 'Se divide por ramas de actividad. Pago quincenal (obrero) y mensual (empleado). El IMGR establece un piso que ninguna categoría puede perforar.'),
(3, '76/75', 'Construcción (UOCRA)', 'Asistencia perfecta (20% s/básico quincenal)', 'Asistencia perfecta = 20% del básico. Fuerte impacto si se pierde.', 'Zonificación, altura, profundidad, aislamiento.', 'Régimen especial (Ley 22.250). NO aplica Ley de Contrato de Trabajo para despido (tiene el Fondo de Cese Laboral — libreta de aportes). Ojo con intimaciones: no aplican multas LCT.'),
(4, '40/89', 'Camioneros', '1% por año (Art. 6.1.1)', 'No general (reemplazado por fijos de rama)', 'Kilometraje, viáticos (Arts. 71/72), cruce de frontera, horas extra al 100% sáb/dom.', 'Régimen de remuneración complejo. Los viáticos son remunerativos para SAC e indemnizaciones de manera proporcional.'),
(5, '389/04', 'Gastronomía y Hotelería (UTHGRA)', '1% a 1.5% anual (según zona/año)', '10% del básico (Asistencia Perfecta Art. 11.2)', 'Alimentación (falla de provisión = 10% adicional), Plus Zona desfavorable, Plus Temporada.', 'Alta conflictividad por \"media jornada\" (art. 92 ter LCT) mal registrada. Convenio que se divide transversalmente por estrellas del local/hotel.'),
(6, '122/75', 'Sanidad (FATSA Clínicas/Sanatorios)', '2% anual (Art. 10)', 'No tiene plus genérico, pero rigen descansos rotativos estrictos', 'Título profesional (Enfermería), Área cerrada (UTI/UCO), Riesgo.', 'Enfermería en terapia intensiva tiene reducción de jornada a 6 horas por insalubridad. Las horas por encima de eso son al 100%.'),
(7, '18/75', 'Bancarios', '1.5% a 2% anual progresivo, remunerativo', 'No general, pero rigen bonos por cumplimiento y objetivos', 'Título, falla de caja, función jerárquica, zona desfavorable.', 'Jornada legal de 7.5 hs. Tienen el \"Bono del Día del Bancario\" (Noviembre) que es muy significativo y debe prorratearse para el despido/SAC.'),
(8, '264/95', 'Seguros (Actividad Aseguradora)', '1% por año (Art. 13)', 'Premio por asistencia', 'Refrigerio/Almuerzo (muy alto), Título universitario, Idioma.', 'Sueldos elevados en comparación con comercio. El adicional por refrigerio es casi siempre remunerativo y pactado en paritarias constantemente.'),
(9, '281/96', 'Maestranza (SOM)', '1% del básico por año', 'Asistencia Perfecta = 15% a 20% (muy relevante en el sueldo)', 'Limpieza en altura, lavado de alfombras, recolección de residuos médicos.', 'Se contrata mucho por jornadas de 4 horas (media jornada real). La pérdida del presentismo impacta enormemente, fuente de litigios frecuentes.'),
(10, 'Ley 26.727', 'Trabajo Agrario (UATRE)', '1% de 1 a 10 años. 1.5% a partir de 10 años.', 'No rige por convenio, sino por acuerdos provinciales de la CNTA.', 'Zonificación, vivienda provista, alimentación, tareas riesgosas (agroquímicos).', 'Régimen propio (Ley 26.727). No aplica la LCT salvo supletorio. Indemnización especial mínima de 2 meses de sueldo (Art. 76). Prohibición del uso de empresas de servicios temporarios.'),
(11, '248/95', 'ASIMRA (Supervisores Metalúrgicos)', '1% por año (Art. 18)', 'Premio asistencia / puntualidad propio de rama', 'Título Secundario/Universitario, Turnos Rotativos.', 'Complementario a UOM. Salarios jerárquicos elevados. Frecuentes gratificaciones extraordinarias y sumas no remunerativas en paritarias.'),
(12, '27/88', 'SMATA (Mecánicos y Afines FAATRA)', '1% por año', 'Premio por Asistencia (10% a 15% s/básico)', 'Título, Viáticos, Tareas Peligrosas.', 'Paritarias muy dinámicas (bimestrales/trimestrales). Incorporación constante de sumas no remunerativas al básico. Diferenciar bien horas normales de extras.'),
(13, '244/94', 'Alimentación (Industria FTIA)', '1% anual acumulativo', 'Premio Asistencia Perfecta (muy estricto)', 'Turnos rotativos, Trabajo nocturno, Adicional Zona (ej. Patagonia).', 'Líneas de producción continuas. Fuerte peso del presentismo y el trabajo en días de descanso (sábados 13hs en adelante al 100%).'),
(14, '371/03', 'Estaciones de Servicio (SOESGyPE Nación)', '2% por año aniversario', 'Asistencia Perfecta (10% s/básico)', 'Manejo de Fondos (Falla de Caja).', 'Régimen de turnos rotativos y trabajo nocturno habitual. El manejo de fondos es fijo y remunerativo.'),
(15, '666/13', 'Estaciones de Servicio Córdoba (SINPECOR)', '1.5% anual (revisar año de ingreso)', 'Asistencia y Puntualidad', 'Manejo de caja, Sumas \"No Remunerativas\" fijadas en paritarias recurrentes.', 'CCT específico provincial (Córdoba). Históricamente negocian un % \"no remunerativo\" alto (12-15%) que incide en el cálculo de adicionales y aguinaldo. Clave para liquidación.'),
(16, 'STVN Nación', 'Viales Nacionales (Dirección Nacional Vialidad)', 'Compensación por años de servicio', 'Sujeto a normativa de Empleo Público Nacional', 'Zona Desfavorable (muy alto en Patagonia), Título, Riesgo.', 'Régimen de Empleo Público. Escalas congeladas por largos periodos recientemente, con exigencias de reapertura paritaria. Viáticos y movilidad son fundamentales.'),
(17, 'SIVIALCO', 'Viales Provincia de Córdoba (SiViCo)', '1% a 2% según régimen provincial', 'Asistencia atada a presentismo estatal', 'Bonificación especial por tarea vial, Desarraigo Campamento.', 'Empleo Provincial. Las paritarias suelen establecer actualizaciones bimestrales atadas al IPC (inflación de Córdoba) como gatillo.'),
(18, '644/12', 'Petroleros Privados (Neuquén/Río Negro/La Pampa)', 'Acorde a antigüedad en empresa/yacimiento', 'Bono por presentismo y paz social', 'Adicional Zona Vaca Muerta (85%), Vianda, Horas Viaje, Bono Productividad.', 'Sueldos más altos del país. El \"Salario Bruto Conformado Mensual Mínimo de Referencia\" supera $1.740.000. Alta incidencia de sumas exentas de Ganancias.'),
(19, '76/75 Z-B', 'Construcción UOCRA (Zona B Neuquén/Río Negro/Chubut)', 'Asistencia perfecta (20% s/básico quincenal)', 'Sumamente relevante. Se pierde ante ausencias injustificadas.', 'Zonificación B (Aumento superior al básico nacional Zona A), Altura, Campamento.', 'A diferencia de Buenos Aires (Zona A), en Zona B (Patagonia) el valor hora es un 20% más alto en promedio. Régimen Ley 22.250 (Libreta de Cese).'),
(20, 'SEP-CBA', 'SEP (Empleados Públicos Pcia. Córdoba)', 'Porcentaje acumulativo anualmente según escalafón', 'Asistencia Perfecta / Adicional Función', 'Riesgo, Insalubridad (Salud), Tareas Específicas, Alta carga Funcional.', 'NO APLICA LCT (Art. 2). Es régimen de Empleo Público. Las escalas y paritarias se ajustan directamente por IPC (Inflación de Córdoba). Alta litigiosidad por Riesgos de Trabajo (LRT sí aplica).'),
(21, 'SUOEM', 'SUOEM (Municipalidad de Córdoba)', '2% del básico por año acumulado', 'Bonificación propia municipal por dedicación', 'Prolongación de jornada (7ma hora), Cargas Familiares, Riesgo.', 'Empleo Público Municipal. Los salarios más altos de la región para estamentos del Estado. Paritarias con indexación salarial garantizada que impacta en pasivos y activos.');

