--
-- Estructura de tabla para la tabla `pro_jurisprudencia`
--

CREATE TABLE `pro_jurisprudencia` (
  `id` int(11) NOT NULL,
  `caratula` varchar(255) NOT NULL,
  `tribunal` varchar(100) NOT NULL,
  `fecha` date NOT NULL,
  `tema` varchar(255) NOT NULL,
  `resumen` text DEFAULT NULL,
  `relevancia` varchar(50) DEFAULT NULL,
  `tipo_conflicto` varchar(100) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `pro_jurisprudencia`
--

INSERT INTO `pro_jurisprudencia` (`id`, `caratula`, `tribunal`, `fecha`, `tema`, `resumen`, `relevancia`, `tipo_conflicto`) VALUES
(1, 'Vizzoti, Carlos Alberto c/ AMSA S.A.', 'CSJN', '2004-09-14', 'Tope Art. 245 LCT', 'Declaró inconstitucional el tope del Art. 245 LCT cuando reduce la base de cálculo en más del 33%. Estableció PISO VIZZOTI: 67% de la mejor remuneración mensual, normal y habitual.', 'fundamental', 'despido_sin_causa'),
(2, 'Aquino, Isacio c/ Cargo Servicios Industriales S.A.', 'CSJN', '2004-09-21', 'Opción vía civil en accidentes laborales', 'Habilitó la acción civil por daños y perjuicios en accidentes laborales, declarando inconstitucional el Art. 39.1 LRT que vedaba la vía civil. Fundamento: reparación integral vs. tarifa.', 'fundamental', 'accidente_laboral'),
(3, 'González, Martín Nicolás c/ Polimat S.A.', 'CSJN', '2010-07-19', 'Sumas no remunerativas en base de cálculo', 'Las sumas pactadas como no remunerativas en acuerdos paritarios deben incluirse en la base de cálculo del Art. 245 LCT cuando tienen naturaleza salarial real.', 'alta', 'diferencias_salariales'),
(4, 'Castillo, Ángel Santos c/ Cerámica Alberdi S.A.', 'CSJN', '2004-09-07', 'Competencia justicia provincial vs. federal en LRT', 'Declaró inconstitucional la competencia federal exclusiva del Art. 46 LRT. El trabajador puede optar por la justicia provincial en reclamos ART.', 'alta', 'accidente_laboral'),
(5, 'Milone, Juan Antonio c/ Asociart S.A.', 'CSJN', '2004-10-26', 'Inconstitucionalidad pago en renta LRT', 'Declaró inconstitucional el sistema de pago periódico (renta) para incapacidades >= 50% de la LRT. Dispuso pago único.', 'alta', 'accidente_laboral'),
(6, 'Pérez, Raúl Aníbal c/ Disco S.A.', 'CSJN', '2009-09-01', 'Concepto de remuneración — Vales de almuerzo', 'Los vales de almuerzo y canasta tienen naturaleza remuneratoria y deben incluirse en la base de cálculo indemnizatorio y previsional.', 'alta', 'diferencias_salariales'),
(7, 'Díaz, Paulo Vicente c/ Cervecería y Maltería Quilmes S.A.', 'CSJN', '2013-03-04', 'Discriminación antisindical — Reinstalación', 'Estableció que la tutela contra la discriminación opera incluso sin ser delegado gremial. Operatividad directa de la Ley 23.592 (antidiscriminación) con reinstalación al puesto.', 'alta', 'despido_sin_causa'),
(8, 'Rica, Carlos Martín c/ Hospital Alemán', 'CSJN', '2018-04-24', 'Médicos de guardia — Relación de dependencia', 'Médicos que realizan guardias asignadas por la institución, con horarios impuestos y bajo subordinación jurídica, son empleados en relación de dependencia. La facturación por monotributo no excluye la laboralidad.', 'alta', 'trabajo_no_registrado');

-- --------------------------------------------------------

--
-- Estructura de tabla para la tabla `pro_normativa`
--

CREATE TABLE `pro_normativa` (
  `id` int(11) NOT NULL,
  `ley` varchar(100) NOT NULL,
  `articulo` varchar(100) DEFAULT NULL,
  `texto` text NOT NULL,
  `estado` varchar(50) DEFAULT 'vigente',
  `fecha_modificacion` date DEFAULT NULL,
  `notas` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `pro_normativa`
--

INSERT INTO `pro_normativa` (`id`, `ley`, `articulo`, `texto`, `estado`, `fecha_modificacion`, `notas`) VALUES
(1, 'LCT 20.744', 'Art. 14 bis CN', '[Protección constitucional del trabajo]\r\nEl trabajo en sus diversas formas gozará de la protección de las leyes, las que asegurarán al trabajador: condiciones dignas y equitativas de labor; jornada limitada; descanso y vacaciones pagados; retribución justa; salario mínimo vital y móvil; igual remuneración por igual tarea; participación en las ganancias de las empresas; protección contra el despido arbitrario; estabilidad del empleado público; organización sindical libre y democrática.', 'vigente', NULL, 'Base constitucional de todo el derecho laboral argentino. Principio protectorio.'),
(2, 'LCT 20.744', 'Art. 1', '[Fuentes de regulación]\r\nEl contrato de trabajo y la relación de trabajo se rigen: a) Por esta ley. b) Por las leyes y estatutos profesionales. c) Por las convenciones colectivas de trabajo. d) Por la voluntad de las partes. e) Por los usos y costumbres.', 'vigente', NULL, 'Jerarquía normativa: Ley > CCT > Contrato individual. Principio de norma más favorable.'),
(3, 'LCT 20.744', 'Art. 4', '[Concepto de trabajo]\r\nConstituye trabajo, a los fines de esta ley, toda actividad lícita que se preste en favor de quien tiene la facultad de dirigirla, mediante una remuneración. El contrato de trabajo tiene como principal objeto la actividad productiva y creadora del hombre en sí.', 'vigente', NULL, 'Define subordinación como nota tipificante. Actividad + dirección + remuneración = relación laboral.'),
(4, 'LCT 20.744', 'Art. 7', '[Condiciones menos favorables — Nulidad]\r\nLas partes, en ningún caso, pueden pactar condiciones menos favorables para el trabajador que las dispuestas en las normas legales, convenciones colectivas de trabajo o laudo con fuerza de tales, o que resulten contrarias a las mismas.', 'vigente', NULL, 'Principio de irrenunciabilidad. Orden público laboral.'),
(5, 'LCT 20.744', 'Art. 9', '[Principio de la norma más favorable — In dubio pro operario]\r\nEn caso de duda sobre la aplicación de normas legales o convencionales prevalecerá la más favorable al trabajador. Si la duda recayese en la interpretación o alcance de la ley, o en apreciación de la prueba en los casos concretos, los jueces o encargados de aplicarla se decidirán en el sentido más favorable al trabajador.', 'vigente', NULL, 'Triple operatividad: norma más favorable, condición más beneficiosa, in dubio pro operario.'),
(6, 'LCT 20.744', 'Art. 10', '[Conservación del contrato]\r\nEn caso de duda las situaciones deben resolverse en favor de la continuidad o subsistencia del contrato.', 'vigente', NULL, 'Principio de continuidad. Preferencia por la estabilidad.'),
(7, 'LCT 20.744', 'Art. 12', '[Irrenunciabilidad]\r\nSerá nula y sin valor toda convención de partes que suprima o reduzca los derechos previstos en esta ley, los estatutos profesionales, las convenciones colectivas de trabajo, ya sea al tiempo de su celebración o de su ejecución, o del ejercicio de derechos provenientes de su extinción.', 'vigente', NULL, 'Irrenunciabilidad absoluta. Excepción: conciliación ante autoridad competente (Art. 15 LCT).'),
(8, 'LCT 20.744', 'Art. 21', '[Contrato de trabajo]\r\nHabrá contrato de trabajo, cualquiera sea su forma o denominación, siempre que una persona física se obligue a realizar actos, ejecutar obras o prestar servicios en favor de la otra y bajo la dependencia de ésta, durante un período determinado o indeterminado de tiempo, mediante el pago de una remuneración.', 'vigente', NULL, 'Primacía de la realidad sobre las formas. No importa cómo se denomine, importa qué es.'),
(9, 'LCT 20.744', 'Art. 22', '[Relación de trabajo]\r\nHabrá relación de trabajo cuando una persona realice actos, ejecute obras o preste servicio en favor de otra, bajo la dependencia de ésta en forma voluntaria y mediante el pago de una remuneración, cualquiera sea el acto que le dé origen.', 'vigente', NULL, 'La relación de trabajo puede existir sin contrato formal.'),
(10, 'LCT 20.744', 'Art. 23', '[Presunción de existencia del contrato de trabajo]\r\nEl hecho de la prestación de servicios hace presumir la existencia de un contrato de trabajo, salvo que por las circunstancias, las relaciones o causas que lo motiven se demostrase lo contrario. Esa presunción operará igualmente aun cuando se utilicen figuras no laborales, para caracterizar al contrato, y en tanto que por las circunstancias no sea dado calificar de empresario a quien presta el servicio.', 'vigente — MODIFICADO por Ley 27.802 (2026)', NULL, 'CLAVE: La Ley 27.802 incorporó 3 controles que debilitan la presunción (facturación + pago bancario + contrato escrito). Si los 3 están presentes, la presunción NO opera automáticamente. Ver Art. 23 Ley 27.802.'),
(11, 'LCT 20.744', 'Art. 26', '[Empleador]\r\nSe considera \"empleador\" a la persona física o conjunto de ellas, o jurídica, tenga o no personalidad jurídica propia, que requiera los servicios de un trabajador.', 'vigente', NULL, 'Concepto amplio. Incluye personas humanas y jurídicas.'),
(12, 'LCT 20.744', 'Art. 29', '[Interposición y mediación — Fraude]\r\nLos trabajadores que habiendo sido contratados por terceros con vista a proporcionarlos a las empresas, serán considerados empleados directos de quien utilice su prestación. En tal supuesto, y cualquiera que sea el acto o estipulación que al efecto concierten, los terceros contratantes y la empresa para la cual los trabajadores presten o hayan prestado servicios responderán solidariamente de todas las obligaciones emergentes de la relación laboral.', 'vigente', NULL, 'Fraude laboral por interposición de persona. El trabajador es empleado directo de quien usa su trabajo. Solidaridad entre intermediario y empresa usuaria.'),
(13, 'LCT 20.744', 'Art. 30', '[Subcontratación y delegación — Solidaridad]\r\nQuienes cedan total o parcialmente a otros el establecimiento o explotación habilitado a su nombre, o contraten o subcontraten, cualquiera sea el acto que le dé origen, trabajos o servicios correspondientes a la actividad normal y específica propia del establecimiento, dentro o fuera de su ámbito, deberán exigir a sus contratistas o subcontratistas el adecuado cumplimiento de las normas relativas al trabajo y los organismos de seguridad social.', 'vigente — MODIFICADO por Ley 27.802 (2026)', NULL, 'CLAVE: La Ley 27.802 definió 5 controles de exención para el principal (CUIL, aportes, pago directo, CBU, ART). Si cumple los 5, queda EXENTO de responsabilidad solidaria. Ver análisis en sistema.'),
(14, 'LCT 20.744', 'Art. 103', '[Concepto de remuneración]\r\nA los fines de esta ley, se entiende por remuneración la contraprestación que debe percibir el trabajador como consecuencia del contrato de trabajo. Dicha remuneración no podrá ser inferior al salario mínimo vital.', 'vigente', NULL, 'Base para todo cálculo indemnizatorio. Incluye todo concepto remunerativo.'),
(15, 'LCT 20.744', 'Art. 103 bis', '[Beneficios sociales]\r\nSe denominan beneficios sociales a las prestaciones de naturaleza jurídica de seguridad social, no remunerativas, no dinerarias, no acumulables ni sustituibles en dinero, que brinda el empleador al trabajador por sí o por medio de terceros.', 'vigente', NULL, 'Diferencia clave entre remunerativo y no remunerativo. Impacta en base de cálculo indemnizatorio.'),
(16, 'LCT 20.744', 'Art. 121/122/123', '[Sueldo Anual Complementario (SAC / Aguinaldo)]\r\nArt. 121: Se entiende por SAC la doceava parte del total de las remuneraciones. Art. 122: Se abona en dos cuotas: 30/06 y 18/12 de cada año. Art. 123: Extinción del contrato: el trabajador tiene derecho al SAC proporcional al tiempo trabajado en el semestre.', 'vigente', NULL, 'SAC = mejor remuneración mensual devengada / 2 x (días trabajados en el semestre / días del semestre). Siempre se debe al extinguir el contrato. Base: mejor remuneración normal y habitual.'),
(17, 'LCT 20.744', 'Art. 150', '[Licencia ordinaria — Duración de vacaciones]\r\nEl trabajador gozará de un período mínimo y continuado de descanso anual remunerado: a) 14 días corridos con antigüedad menor a 5 años. b) 21 días corridos con antigüedad de 5 a 10 años. c) 28 días corridos con antigüedad de 10 a 20 años. d) 35 días corridos con antigüedad mayor a 20 años.', 'vigente', NULL, 'La antigüedad se computa al 31/12 del año que correspondan. Se requiere haber prestado servicios la MITAD de los días hábiles del año calendario. Si no se alcanza, 1 día cada 20 trabajados.'),
(18, 'LCT 20.744', 'Art. 156', '[Indemnización por vacaciones no gozadas]\r\nCuando por cualquier causa se produjera la extinción del contrato de trabajo, el trabajador tendrá derecho a percibir una indemnización equivalente al salario correspondiente al período de descanso proporcional a la fracción del año trabajada.', 'vigente', NULL, 'Se calcula igual que las vacaciones pero con base en el salario al momento de la extinción.'),
(19, 'LCT 20.744', 'Art. 196', '[Jornada de trabajo — Determinación]\r\nLa extensión de la jornada de trabajo es uniforme para toda la Nación y se regirá por la ley 11.544, con exclusión de toda disposición provincial en contrario.', 'vigente', NULL, 'Ley 11.544: 8 hs diarias / 48 hs semanales. Nocturna: 7 hs. Insalubre: 6 hs.'),
(20, 'LCT 20.744', 'Art. 201', '[Horas extraordinarias]\r\nEl empleador deberá abonar al trabajador que prestare servicios en horas suplementarias, medie o no autorización del organismo administrativo competente, un recargo del 50% calculado sobre el salario habitual, si se tratare de días comunes, y del 100% en días sábado después de las 13 horas, domingo y feriados.', 'vigente', NULL, 'Horas extra: 50% días hábiles, 100% sábados/domingos/feriados. Base de cálculo: salario habitual.'),
(21, 'LCT 20.744', 'Art. 231', '[Preaviso — Plazos]\r\nEl contrato de trabajo no podrá ser disuelto por voluntad de una de las partes, sin previo aviso, o en su defecto, indemnización además de la que corresponda al trabajador por su antigüedad en el empleo. El preaviso, cuando las partes no lo fijen en un plazo mayor, deberá darse con la anticipación siguiente: a) Por el trabajador, de QUINCE (15) días. b) Por el empleador, de QUINCE (15) días cuando el trabajador se encontrare en período de prueba; de UN MES cuando la antigüedad no exceda de CINCO (5) años y de DOS MESES cuando fuere superior.', 'vigente', NULL, 'Si no se otorga preaviso, corresponde indemnización sustitutiva. Se integra con SAC proporcional sobre el preaviso.'),
(22, 'LCT 20.744', 'Art. 232', '[Indemnización sustitutiva del preaviso]\r\nLa parte que omita el preaviso o lo otorgue de modo insuficiente deberá abonar a la otra una indemnización sustitutiva equivalente a la remuneración que correspondería al trabajador durante los plazos señalados en el artículo 231.', 'vigente', NULL, 'Equivale al salario de 1 o 2 meses según antigüedad (< o > 5 años).'),
(23, 'LCT 20.744', 'Art. 233', '[Integración del mes de despido]\r\nLos plazos del artículo 231 correrán a partir del primer día del mes siguiente al de la notificación del preaviso. Cuando la extinción del contrato de trabajo dispuesta por el empleador se produzca sin preaviso y en fecha que no coincida con el último día del mes, la indemnización sustitutiva debida al trabajador se integrará con una suma igual a los salarios por los días faltantes hasta el último día del mes en el que se produjera el despido.', 'vigente', NULL, 'Si despide el día 15, paga del 16 al 30/31 como integración. Genera SAC proporcional.'),
(24, 'LCT 20.744', 'Art. 242', '[Justa causa del despido]\r\nUna de las partes podrá hacer denuncia del contrato de trabajo en caso de inobservancia por parte de la otra de las obligaciones resultantes del mismo que configuren injuria y que, por su gravedad, no consienta la prosecución de la relación.', 'vigente', NULL, 'La valoración de la injuria la hace el juez. Proporcionalidad entre falta y sanción. Contemporaneidad: la sanción debe ser inmediata al conocimiento de la falta.'),
(25, 'LCT 20.744', 'Art. 245', '[Indemnización por antigüedad o despido]\r\nEn los casos de despido dispuesto por el empleador sin justa causa, habiendo o no mediado preaviso, éste deberá abonar al trabajador una indemnización equivalente a UN MES de sueldo por cada año de servicio o fracción mayor de TRES meses, tomando como base la mejor remuneración mensual, normal y habitual devengada durante el último año o durante el tiempo de prestación de servicios si éste fuera menor.', 'vigente', NULL, 'FÓRMULA: Mejor remuneración × años de antigüedad (mínimo 1). BASE: mejor remuneración NORMAL y HABITUAL del último año. TOPE: 3 x salario CCT promedio mensual del puesto. PISO: 67% del primer mes de la base (fallo Vizzoti CSJN). NO incluye SAC, vacaciones no gozadas ni previsión horas extra.'),
(26, 'LCT 20.744', 'Art. 246', '[Despido indirecto]\r\nCuando el trabajador hiciese denuncia del contrato de trabajo fundado en justa causa, tendrá derecho a las indemnizaciones previstas en los artículos 232, 233 y 245.', 'vigente', NULL, 'El trabajador se considera despedido por culpa del empleador. Requiere intimación previa (telegrama). Debe acreditar la injuria.'),
(27, 'LCT 20.744', 'Art. 247', '[Despido por fuerza mayor o disminución de trabajo]\r\nEn los casos en que el despido fuese dispuesto por causa de fuerza mayor o por falta o disminución de trabajo no imputable al empleador fehacientemente justificada, el trabajador tendrá derecho a percibir una indemnización equivalente a la MITAD de la prevista en el artículo 245.', 'vigente', NULL, 'Indemnización reducida al 50%. Carga probatoria: empleador. Orden de antigüedad inverso.'),
(28, 'LCT 20.744', 'Art. 248', '[Indemnización por fallecimiento del trabajador]\r\nEn caso de muerte del trabajador, las personas enumeradas en el artículo 38 del Decreto-ley 18.037/69 tendrán derecho, mediante la sola acreditación del vínculo, en el orden y prelación allí establecido, a percibir una indemnización igual a la prevista en el artículo 247 de esta ley.', 'vigente', NULL, 'Indemnización = 50% del Art. 245. Beneficiarios: cónyuge, hijos, ascendientes.'),
(29, 'LCT 20.744', 'Art. 255', '[Reingreso del trabajador — Deducción]\r\nLa antigüedad del trabajador se establecerá conforme a lo dispuesto en los artículos 18 y 19 de esta ley, pero si el trabajador que reingresa a las órdenes del mismo empleador hubiere recibido gratificación por cese de servicios en la oportunidad anterior, la suma correspondiente será deducida de la que le corresponda.', 'vigente', NULL, 'Evita doble cobro. Deduce la indemnización anterior del mismo empleador.'),
(30, 'LCT 20.744', 'Art. 80', '[Deber de entregar certificados de trabajo]\r\nCuando el contrato de trabajo se extinguiere por cualquier causa, el empleador estará obligado a entregar al trabajador un certificado de trabajo. Si el empleador no hiciera entrega de la constancia o del certificado previstos dentro de los TREINTA (30) días corridos de extinguido el contrato de trabajo, el trabajador podrá requerir el cumplimiento. En caso de incumplimiento, el empleador será sancionado con una indemnización a favor del trabajador equivalente a TRES veces la mejor remuneración mensual, normal y habitual devengada.', 'vigente', NULL, 'Multa: 3 sueldos. Requisitos: intimar por TCL DESPUÉS de 30 días. No fue derogada por Ley Bases 27.742. Certificado incluye: datos personales, categoría, remuneraciones, aportes.'),
(31, 'LCT 20.744', 'Art. 256', '[Prescripción — Plazo]\r\nPrescriben a los DOS (2) años las acciones relativas a créditos provenientes de las relaciones individuales de trabajo y, en general, de disposiciones de convenios colectivos, laudos con eficacia de convenios colectivos y disposiciones legales o reglamentarias del Derecho del Trabajo.', 'vigente', NULL, 'PLAZO CRÍTICO: 2 años desde que cada crédito es exigible. Se interrumpe por actuaciones administrativas (SECLO) o judiciales. Se suspende por interpelación fehaciente (telegrama) por 6 meses.'),
(32, 'LCT 20.744', 'Art. 260', '[Pago insuficiente]\r\nEl pago insuficiente de obligaciones originadas en las relaciones laborales efectuado por un empleador será considerado como entrega a cuenta del total adeudado, aunque se reciba sin reservas, y quedará expedita la acción del trabajador para reclamar el pago de la diferencia que correspondiere, por todo el tiempo de la prescripción.', 'vigente', NULL, 'Protege diferencias salariales retroactivas. El cobro sin reserva NO implica renuncia. Clave para reclamos por mala categorización, horas extra impagas, etc.'),
(33, 'Ley 27.802', 'Art. 1', '[Objeto]\r\nLa presente ley tiene por objeto simplificar y modernizar el régimen sancionatorio del empleo no registrado, promoviendo la formalización laboral y sustituyendo el sistema de multas de las Leyes 24.013 y 25.323.', 'vigente', NULL, 'Deroga explícitamente los arts. 8, 9, 10 y 15 de la Ley 24.013 y los arts. 1 y 2 de la Ley 25.323. Establece un régimen nuevo basado en fraude y daño, no en multas.'),
(34, 'Ley 27.802', 'Art. 23 LCT (mod.)', '[Presunción de existencia — Controles de desactivación]\r\nEl hecho de la prestación de servicios hace presumir la existencia de un contrato de trabajo. Sin embargo, cuando se acrediten conjuntamente los siguientes elementos, la presunción NO operará automáticamente: 1) Existencia de facturación regular por parte del prestador de servicios. 2) Pagos bancarios documentados al prestador. 3) Contrato escrito formalizado entre las partes.', 'vigente', NULL, 'CLAVE DEL SISTEMA: Los 3 controles son ACUMULATIVOS. Si falta 1, la presunción OPERA. Si los 3 están presentes, se invierte la carga: el trabajador debe probar subordinación efectiva. No elimina la relación laboral, solo cambia la carga probatoria. Facturación: monotributo, servicios, etc. Pago bancario: transferencias, no efectivo. Contrato escrito: locación de servicios, locación de obra, etc.'),
(35, 'Ley 27.802', 'Análisis: Presunción — 0 controles', '[Escenario: Sin documentación contradictoria]\r\nSi no existen facturación, pago bancario ni contrato escrito: PRESUNCIÓN MÁXIMA. La relación laboral se presume en los términos más amplios. Recomendación: Acreditar subordinación por testigos, horarios, órdenes de trabajo.', 'vigente', NULL, 'Caso más favorable para el trabajador. Posición procesal fuerte.'),
(36, 'Ley 27.802', 'Análisis: Presunción — 3 controles', '[Escenario: 3 elementos presentes (no opera)]\r\nSi existen los 3 controles (facturación + pago bancario + contrato escrito): PRESUNCIÓN NO OPERA. Sin embargo, la relación laboral puede existir igual. El trabajador debe PROBAR: subordinación jurídica, económica y técnica. Elementos: órdenes, horario impuesto, exclusividad, herramientas del principal, etc.', 'vigente', NULL, 'No significa que NO hay relación laboral. Solo que la carga probatoria se invierte. Doctrina: \"Primacía de la realidad\" sigue vigente (Art. 14 LCT).'),
(37, 'Ley 27.802', 'Art. 30 LCT (mod.)', '[Exención de solidaridad — 5 controles]\r\nEl principal que contrate o subcontrate trabajos o servicios correspondientes a la actividad normal y específica quedará EXENTO de responsabilidad solidaria cuando acredite haber ejercido los siguientes controles: 1) Verificación del CUIL de los trabajadores del contratista. 2) Control de aportes a la seguridad social (SRT). 3) Pago de nómina directo a los trabajadores (no a intermediarios). 4) Verificación de CBU del trabajador. 5) Cobertura ART vigente del contratista.', 'vigente', NULL, 'Los 5 controles son ACUMULATIVOS para la exención total. Si faltan controles: solidaridad PROPORCIONAL al riesgo. 5/5 = EXENTO. 4/5 = Factor 2. 3/5 = Factor 3. 2/5 = Factor 4. 1/5 = Factor 5. 0/5 = Factor 6.'),
(38, 'Ley 27.802', 'Fraude Laboral', '[Nuevo régimen de fraude — Sustituye multas]\r\nEl encuadramiento fraudulento de una relación laboral bajo figuras no laborales (monotributo, locación de servicios, cooperativas, etc.) constituye fraude laboral en los términos del Art. 14 LCT. Consecuencias: - Se considera relación laboral plena desde el inicio real. - Registración retroactiva obligatoria. - Daños y perjuicios adicionales (daño complementario). - NO aplican las multas de las leyes derogadas (24.013 / 25.323).', 'vigente', NULL, 'Cambio de paradigma: de \"multa tarifada\" a \"daño real acreditado\". El juez puede fijar el daño complementario según la situación concreta. Más flexible para el juez, pero requiere mayor prueba del trabajador.'),
(39, 'Ley 27.802', 'Daño Complementario', '[Reparación por daño real del empleo no registrado]\r\nEl trabajador que acredite que la falta de registración o la registración deficiente le causó un daño concreto podrá reclamar la reparación del daño complementario, que incluye: - Pérdida de aportes jubilatorios no efectuados. - Pérdida de cobertura de obra social. - Daño moral por la situación de informalidad. - Lucro cesante por la diferencia entre lo cobrado y lo debido.', 'vigente', NULL, 'Reemplaza las multas fijas de la Ley 24.013. Ventaja: puede superar las multas antiguas si el daño es grande. Desventaja: requiere prueba del daño concreto (no es automático). El juez evalúa cada caso. No hay topes tarifados.'),
(40, 'Ley 24.013 (DEROGADA parcialmente)', 'Arts. 8, 9, 10, 15', '[Multas por empleo no registrado — DEROGADAS]\r\nArt. 8: Multa = 25% de las remuneraciones devengadas desde el inicio. Art. 9: Deficiente registración de fecha = diferencia de remuneraciones. Art. 10: Deficiente registración de remuneración = 25% diferencia. Art. 15: Duplicación de multas si no registra tras intimación.', 'DEROGADO por Ley 27.802 (2026)', NULL, 'PRECAUCIÓN: Para hechos ANTERIORES a la vigencia de la Ley 27.802, las multas de la 24.013 pueden seguir siendo aplicables bajo el principio de derecho transitorio (norma más favorable / ultractividad). Consultar caso por caso.'),
(41, 'Ley 25.323 (DEROGADA)', 'Arts. 1 y 2', '[Incremento indemnizatorio — DEROGADO]\r\nArt. 1: Las indemnizaciones previstas por los Arts. 245, 232, 233 LCT serán incrementadas al doble cuando se trate de una relación laboral no registrada. Art. 2: Incremento del 50% si el empleador no paga indemnización y el trabajador debe iniciar acción judicial o administrativa.', 'DEROGADO por Ley 27.802 (2026)', NULL, 'El Art. 2 (50% por mora) también fue derogado. Ahora la reparación es por \"daño complementario\" real, no tarifado. Para hechos anteriores: consultar derecho transitorio.'),
(42, 'Ley 24.557', 'Art. 6', '[Contingencias cubiertas]\r\n1. Se consideran contingencias: a) Accidentes de trabajo: todo acontecimiento súbito y violento ocurrido por el hecho o en ocasión del trabajo, o en el trayecto (in itinere). b) Enfermedades profesionales: aquellas incluidas en el listado elaborado por el Poder Ejecutivo Nacional. 2. No se consideran enfermedades profesionales las ajenas al listado, salvo que se demuestre causalidad directa entre agente de riesgo y enfermedad.', 'vigente', NULL, 'In itinere: trayecto habitual domicilio-trabajo-domicilio. Sin desvíos por interés personal. Enfermedades NO listadas pueden reclamarse judicialmente demostrando causalidad (SCJN: \"Silva, Facundo\" y otros).'),
(43, 'Ley 24.557', 'Art. 11', '[Régimen de incapacidades]\r\nLos damnificados percibirán las siguientes prestaciones dinerarias: a) Incapacidad Laboral Temporaria (ILT): salario completo durante el período de recuperación, con un máximo de 2 años. b) Incapacidad Laboral Permanente (ILP): prestación de pago mensual o pago único según el grado de incapacidad.', 'vigente', NULL, 'ILT: primeros 10 días paga el empleador, luego la ART. Máximo 2 años. Si persiste, se evalúa ILP. ILP Parcial Provisoria (<50%): pago mensual = salario × %incapacidad × 13/12. ILP Total (>66%): adicional por gran invalidez.'),
(44, 'Ley 24.557', 'Art. 14.2.a', '[Prestación por Incapacidad Permanente Definitiva (IPD)]\r\nCuando el porcentaje de incapacidad sea permanente y definitivo, el damnificado percibirá un pago único según la fórmula: 53 × IBM × (65/Edad) × (%Incapacidad/100) donde IBM = Ingreso Base Mensual.', 'vigente — complementado por Ley 26.773', NULL, 'Fórmula LRT: 53 × IBM × (65/Edad) × %Incap. IBM: promedio de remuneraciones sujetas a aportes de los 12 meses anteriores. Ley 26.773 agrega pisos mínimos actualizados por RIPTE. ADVERTENCIA: los pisos se recalculan periódicamente (último: Sep 2025). Si la fórmula da menos que el piso RIPTE, se aplica el piso.'),
(45, 'Ley 24.557', 'Art. 15', '[Prestaciones por IPP (Incapacidad Parcial Permanente)]\r\nSi el porcentaje de incapacidad es inferior al 50% y definitiva: pago único. Si es igual o superior al 50% e inferior al 66%: pago mensual complementario de la prestación jubilatoria. Si es igual o superior al 66%: prestación como incapacidad total.', 'vigente', NULL, 'Rangos clave: <50% IPP: pago único (fórmula art. 14.2.a). 50-65% IPP: pago mensual complementario. >=66%: gran invalidez (adicional art. 17). Los pisos RIPTE aplican a cada rango.'),
(46, 'Ley 24.557', 'Art. 17', '[Gran invalidez]\r\nEl damnificado declarado gran inválido percibirá las prestaciones correspondientes a los artículos 14.2 y 15, según el caso, con más una prestación de pago mensual adicional equivalente a 3 MOPRE. En ningún caso esta prestación será inferior al monto del SMVM.', 'vigente', NULL, 'Gran invalidez: >=66% de incapacidad + necesidad de asistencia permanente. Triple prestación: pago único + mensual + adicional por gran invalidez. Piso RIPTE específico: actualmente ~$9.040.000 (2025).'),
(47, 'Ley 24.557', 'Art. 18', '[Muerte del trabajador]\r\nLos derechohabientes accederán a la pensión por fallecimiento prevista en el régimen previsional. Además, percibirán un pago único según la fórmula del artículo 14.2.a, con los pisos actualizados.', 'vigente', NULL, 'Piso RIPTE específico muerte: ~$6.780.000 (2025). Beneficiarios: cónyuge, hijos menores.'),
(48, 'Ley 27.348', 'Art. 1', '[Procedimiento ante Comisiones Médicas]\r\nLos trabajadores siniestrados deberán someterse al trámite ante las Comisiones Médicas jurisdiccionales como instancia administrativa PREVIA y OBLIGATORIA para acceder a la vía judicial.', 'vigente', NULL, 'Paso obligatorio antes de demandar judicialmente. Comisión Médica Jurisdiccional (CMJ) determina: %incapacidad, tratamiento, alta. Si no hay acuerdo: recurso ante Comisión Médica Central (CMC) o vía judicial. PLAZO para impugnar: varía por provincia (CABA: 30 días, Bs.As.: 90 días).'),
(49, 'Ley 27.348', 'Art. 2', '[Recurso contra dictamen de CM]\r\nEl trabajador que no estuviere de acuerdo con el dictamen de la Comisión Médica Jurisdiccional podrá interponer recurso ante la Comisión Médica Central o ante el Juzgado Federal de Primera Instancia con competencia en el domicilio de la CMJ que intervino.', 'vigente', NULL, 'Dos vías de recurso: 1) CMC: recurso administrativo (más rápido). 2) Justicia Federal: recurso judicial (peritaje independiente). PLAZO CABA: 30 días desde notificación del dictamen. PLAZO Buenos Aires: 90 días. CADUCIDAD: si no se recurre en plazo, el dictamen queda firme.'),
(50, 'Ley 26.773', 'Art. 8', '[Pisos mínimos con ajuste RIPTE]\r\nLos importes por incapacidad laboral permanente y muerte del trabajador serán actualizados semestralmente por el índice RIPTE (Remuneraciones Imponibles Promedio de los Trabajadores Estables). La ART no podrá abonar una suma inferior al piso mínimo vigente.', 'vigente', NULL, 'Pisos actuales (ref. Sep 2025): IPP parcial: $2.260.000 IPD: $4.520.000 Gran invalidez: $9.040.000 Muerte: $6.780.000 Se actualizan por Res. SRT con base RIPTE semestral.'),
(51, 'Ley 26.773', 'Art. 4', '[Opción excluyente — Vía civil]\r\nEl damnificado o sus derechohabientes podrán optar de modo excluyente entre la reparación tarifada del sistema de riesgos del trabajo o la acción civil por daños y perjuicios en la vía judicial civil.', 'vigente', NULL, 'OPCIÓN EXCLUYENTE: si elige vía civil, PIERDE la tarifa ART. Vía civil permite: daño moral, daño estético, lucro cesante integral. Fórmulas civiles: Méndez, Vuotto, Marshall. La civil puede dar montos 2x-3x superiores pero con mayor riesgo probatorio.'),
(52, 'Ley 24.557', 'Art. 6.3 — Preexistencias', '[Incapacidad preexistente — Fórmula de Balthazard]\r\nLas incapacidades preexistentes se computan según la fórmula de Balthazard: Incapacidad Resultante = 1 - (1 - Incapacidad Actual) / (1 - Preexistencia). La ART solo responde por la incapacidad NO preexistente.', 'vigente', NULL, 'Fórmula Balthazard: permite calcular incapacidad NETA descontando preexistencia. Ejemplo: Incapacidad total 40%, preexistencia 20%: Neta = 1 - (1-0.40)/(1-0.20) = 1 - 0.60/0.80 = 1 - 0.75 = 25%. La ART responde por 25%, no por 40%.'),
(53, 'Ley 27.742 (Ley Bases)', 'Art. 76 — Período de Prueba', '[Extensión del período de prueba]\r\nSe modifica el Art. 92 bis de la LCT. El período de prueba se establece en SEIS (6) meses, extensible a OCHO (8) meses por CCT para empresas de 6 a 100 trabajadores, y a DOCE (12) meses por CCT para empresas de hasta 5 trabajadores.', 'vigente desde 09/07/2024', NULL, 'Antes: 3 meses universales. Ahora: 6 meses base, 8/12 por CCT. Durante el período de prueba: despido sin causa sin indemnización. Impacto en cálculos: si el despido ocurre en período de prueba, NO corresponde Art. 245. Solo preaviso de 15 días.'),
(54, 'Ley 27.742 (Ley Bases)', 'Art. 80 — Fondo de Cese', '[Sistema de Fondo de Cese Laboral Sectorial]\r\nSe habilita la creación de un Fondo de Cese Laboral por CCT, que sustituye al régimen indemnizatorio de los Arts. 232, 233 y 245 LCT. El fondo se nutre de aportes mensuales del empleador. El trabajador accede al fondo al producirse el cese laboral.', 'vigente — pendiente reglamentación por CCT', NULL, 'Similar al sistema UOCRA (Ley 22.250). Requiere adhesión por CCT. No es obligatorio: cada CCT decide si lo implementa. Si el CCT NO adhiere, sigue el régimen general de Arts. 232/233/245. IMPORTANTE: pocos CCTs han implementado esto aún.'),
(55, 'Ley 27.742 (Ley Bases)', 'Art. 78 — Trabajador Independiente con Colaboradores', '[Nueva figura: Trabajador independiente con hasta 3 colaboradores]\r\nSe crea la figura del trabajador independiente que puede contar con hasta TRES (3) trabajadores independientes para llevar adelante un emprendimiento productivo, sin que entre ellos exista relación de dependencia.', 'vigente — sujeto a reglamentación', NULL, 'Figura controvertida. Riesgo de encubrimiento de relación laboral. Los \"colaboradores\" no tienen derechos laborales ni previsionales plenos. Doctrina laboral: evaluar subordinación real (Art. 23 LCT / Ley 27.802). Si hay órdenes, horario, exclusividad = relación laboral encubierta.'),
(56, 'Ley 27.742 (Ley Bases)', 'Art. 81 — Bloqueos y piquetes', '[Causal de despido por bloqueo, piquete o toma]\r\nSe considera justa causa de despido la participación activa en bloqueos o tomas de establecimientos, cuando impidan el ingreso o egreso de personas o bienes al establecimiento.', 'vigente', NULL, 'Amplia causal de despido con causa. Requiere participación \"activa\". La mera participación pasiva o sindical NO debería configurar causal. Conflicto con derecho de huelga (Art. 14 bis CN). Sujeto a control judicial.'),
(57, 'Ley 27.742 (Ley Bases)', 'Fecha de corte', '[Aplicación temporal — 09/07/2024]\r\nLa Ley 27.742 entró en vigencia el 09/07/2024. Las modificaciones aplican a hechos posteriores a esa fecha. Los derechos adquiridos bajo el régimen anterior se mantienen.', 'vigente', NULL, 'Para el motor: validar si fecha_extinción > 09/07/2024. Si es ANTERIOR: aplica régimen completo anterior (multas 24.013, período prueba 3 meses, etc.). Si es POSTERIOR: aplica Ley Bases + Ley 27.802. CLAVE para derecho transitorio.'),
(58, 'Decreto 1694/2009', 'Reglamentación LRT', '[Reglamentación Ley 26.773 — Pisos RIPTE]\r\nEstablece el mecanismo de actualización semestral de los pisos mínimos de prestaciones dinerarias de la LRT mediante el índice RIPTE. La SRT publica los montos actualizados mediante resolución.', 'vigente', NULL, 'Los pisos se actualizan: Enero y Julio de cada año. Publicación: Resolución SRT en Boletín Oficial.'),
(59, 'Decreto 351/1979', 'Reglamentación Ley 19.587', '[Higiene y Seguridad en el Trabajo]\r\nReglamentación de la Ley 19.587 de Higiene y Seguridad en el Trabajo. Establece condiciones mínimas de prevención: iluminación, ventilación, ruido, protección contra incendios, señalización, provisión de EPP, servicios de medicina laboral, exámenes preocupacionales y periódicos.', 'vigente', NULL, 'El incumplimiento del Decreto 351/79 es prueba instrumental importante en juicios por accidentes laborales. Si el empleador no cumplía con prevención, aumenta responsabilidad y puede habilitar vía civil. Incluye anexos técnicos con valores límite de exposición a agentes.'),
(60, 'Decreto 467/2014', 'Reglamentación Ley 26.773', '[Procedimiento de cobro de prestaciones LRT]\r\nReglamenta el trámite para la percepción de las prestaciones dinerarias: plazo de pago de 15 días desde la homologación del acuerdo, modalidad de pago mediante depósito bancario a nombre del damnificado.', 'vigente', NULL, 'La ART tiene 15 días para pagar desde que se homologa.'),
(61, 'Decreto 49/2014', 'Listado de Enfermedades Profesionales', '[Actualización del Listado de Enfermedades Profesionales]\r\nActualiza el listado del Art. 6.2 de la Ley 24.557, incorporando nuevas enfermedades profesionales y sus agentes de riesgo. Include trastornos musculoesqueléticos, hipoacusia, enfermedades respiratorias por exposición a agentes, entre otras.', 'vigente', NULL, 'El listado es cerrado. Enfermedades NO listadas requieren prueba pericial de causalidad directa. Tendencia jurisprudencial: ampliar vía judicial.'),
(62, 'Res. SRT 886/2015', 'Protocolo de exámenes médicos', '[Exámenes médicos obligatorios]\r\nEstablece el protocolo de exámenes médicos en salud: a) Preocupacional: obligatorio ANTES del ingreso. b) Periódico: según agentes de riesgo del puesto. c) De egreso: optativo, dentro de 10 días del cese. d) Por ausencias prolongadas. e) Previos a transferencia de actividad.', 'vigente', NULL, 'El examen preocupacional es OBLIGATORIO. Sin él, el empleador no puede alegar preexistencias. Es clave en juicios por accidentes para determinar estado de salud al ingreso.'),
(63, 'Res. SRT 905/2015', 'Procedimiento CM', '[Procedimiento ante Comisiones Médicas]\r\nReglamenta el procedimiento ante las Comisiones Médicas jurisdiccionales: Plazos, presentación de documentación, pericias, notificaciones, audiencias médicas y dictamen final.', 'vigente', NULL, 'Plazo para citación: dentro de los 10 días de la presentación. El dictamen incluye: diagnóstico, incapacidad %, causalidad, tratamiento. Recurso: dentro del plazo provincial.'),
(64, 'CSJN', 'Vizzoti c/ AMSA (2004)', '[Inconstitucionalidad del tope Art. 245 LCT]\r\nLa CSJN declaró inconstitucional el tope del Art. 245 LCT cuando reduce la base de cálculo en más del 33%. Estableció que el tope no puede representar menos del 67% de la mejor remuneración mensual, normal y habitual.', 'vigente — leading case', NULL, 'PISO VIZZOTI: 67% de la mejor remuneración. Si el tope CCT reduce la base a menos del 67%, se aplica el 67%. Aplicable a todos los despidos sin causa. Ejemplo: salario $1.000.000, tope CCT $500.000 → se aplica $670.000 (67%).'),
(65, 'CSJN', 'Aquino c/ Cargo S.A. (2004)', '[Opción por vía civil en accidentes laborales]\r\nLa CSJN habilitó la vía civil para reclamos por accidentes de trabajo, declarando la inconstitucionalidad del Art. 39.1 LRT que vedaba la acción civil. Abrió el camino para la reparación integral.', 'vigente — leading case', NULL, 'Fundamento: la tarifa LRT puede ser insuficiente para reparar el daño. Hoy regulado por Art. 4 Ley 26.773 (opción excluyente). Clave para el escenario D del sistema (Acción Civil Complementaria).'),
(66, 'CSJN', 'González c/ Polimat (2010)', '[Rubros no remunerativos en base de cálculo]\r\nLa CSJN estableció que las sumas abonadas como no remunerativas (mediante acuerdos paritarios) deben incluirse en la base de cálculo de la indemnización del Art. 245 LCT cuando tienen naturaleza remuneratoria.', 'vigente — leading case', NULL, 'Impacta en la base de cálculo: todo lo que tiene naturaleza salarial debe incluirse como remunerativo. Los acuerdos que \"disfrazan\" aumentos como no remunerativos son cuestionables.'),
(67, 'CSJN', 'Castillo c/ Cerámica Alberdi (2004)', '[Competencia federal vs. local en reclamos LRT]\r\nDeclaró la inconstitucionalidad del Art. 46 de la LRT que otorgaba competencia federal exclusiva, permitiendo optar por la justicia provincial.', 'vigente — leading case (complementado por Ley 27.3', NULL, 'Post Ley 27.348: primero Comisión Médica, luego justicia federal O provincial. La opción del trabajador por la justicia provincial es constitucional.');

