--
-- Estructura de tabla para la tabla `ripte_sincronizaciones`
--

CREATE TABLE `ripte_sincronizaciones` (
  `id` int(11) NOT NULL,
  `fecha_sincronizacion` timestamp NULL DEFAULT current_timestamp(),
  `tipo_fuente` enum('SRT_API','GOB_AR','fallback_local','manual') DEFAULT 'SRT_API',
  `registros_nuevos` int(11) DEFAULT 0,
  `registros_actualizados` int(11) DEFAULT 0,
  `registros_ignorados` int(11) DEFAULT 0,
  `estado` enum('exitoso','parcial','error','pendiente') DEFAULT 'pendiente',
